1	/**
2	 * Yoke HTTP API server (Node.js built-in http).
3	 *
4	 * This module will be migrated to Fastify when the full HTTP + WS server is
5	 * scaffolded. For now it uses Node's built-in http module so that no new
6	 * package dependency is required for this feature.
7	 *
8	 * Implemented routes (all read-only — AC-6):
9	 *
10	 *   GET /api/sessions/:id/log?sinceSeq=N&limit=M
11	 *     Returns frames N+1..N+M from the session's JSONL log file.
12	 *     Reads directly from the JSONL file on disk (RC-3).
13	 *     SQLite is used only to look up sessions.session_log_path.
14	 *
15	 *     200 { entries: string[], nextSeq: number, hasMore: boolean }
16	 *     200 { entries: [], nextSeq: 0, hasMore: false } — session exists but
17	 *         no log yet (session_log_path is null or file not yet created).
18	 *     404 { error: "session not found" } — no sessions row with that id.
19	 *
20	 * No write or delete paths are exposed.
21	 */
22	
23	import * as http from 'http';
24	import type { DbPool } from '../storage/db.js';
25	import { readLogPage } from '../session-log/reader.js';
26	
27	// ---------------------------------------------------------------------------
28	// Internal helpers
29	// ---------------------------------------------------------------------------
30	
31	function writeJson(res: http.ServerResponse, status: number, body: unknown): void {
32	  const payload = JSON.stringify(body);
33	  res.writeHead(status, {
34	    'Content-Type': 'application/json',
35	    'Content-Length': Buffer.byteLength(payload),
36	  });
37	  res.end(payload);
38	}
39	
40	function parseIntParam(value: string | null, defaultValue: number): number {
41	  if (value === null || value === '') return defaultValue;
42	  const parsed = parseInt(value, 10);
43	  return Number.isFinite(parsed) ? parsed : defaultValue;
44	}
45	
46	// ---------------------------------------------------------------------------
47	// Route: GET /api/sessions/:id/log
48	// ---------------------------------------------------------------------------
49	
50	/** Pattern matching /api/sessions/<id>/log exactly. */
51	const SESSION_LOG_PATTERN = /^\/api\/sessions\/([^/]+)\/log$/;
52	
53	interface SessionRow {
54	  session_log_path: string | null;
55	}
56	
57	async function handleSessionLog(
58	  req: http.IncomingMessage,
59	  res: http.ServerResponse,
60	  db: DbPool,
61	  sessionId: string,
62	  query: URLSearchParams,
63	): Promise<void> {
64	  const sinceSeq = Math.max(0, parseIntParam(query.get('sinceSeq'), 0));
65	  const limit = Math.max(1, parseIntParam(query.get('limit'), 100));
66	
67	  const row = db
68	    .reader()
69	    .prepare('SELECT session_log_path FROM sessions WHERE id = ?')
70	    .get(sessionId) as SessionRow | undefined;
71	
72	  if (!row) {
73	    writeJson(res, 404, { error: 'session not found' });
74	    return;
75	  }
76	
77	  if (!row.session_log_path) {
78	    // Session exists but log path not yet set — no entries yet.
79	    writeJson(res, 200, { entries: [], nextSeq: sinceSeq, hasMore: false });
80	    return;
81	  }
82	
83	  const page = await readLogPage(row.session_log_path, sinceSeq, limit);
84	  if (!page) {
85	    // Path stored in SQLite but file not yet created (session just spawned).
86	    writeJson(res, 200, { entries: [], nextSeq: sinceSeq, hasMore: false });
87	    return;
88	  }
89	
90	  writeJson(res, 200, page);
91	}
92	
93	// ---------------------------------------------------------------------------
94	// Server factory
95	// ---------------------------------------------------------------------------
96	
97	/**
98	 * Creates the Yoke HTTP server.
99	 *
100	 * @param db  DbPool opened by the caller. The server uses db.reader() for
101	 *            all SELECT queries; no writes are performed.
102	 */
103	export function createHttpServer(db: DbPool): http.Server {
104	  return http.createServer(async (req, res) => {
105	    // new URL() (non-deprecated) for URL parsing; base is required but ignored
106	    // for path/query extraction on relative request URLs.
107	    const reqUrl = new URL(req.url ?? '/', 'http://localhost');
108	    const pathname = reqUrl.pathname;
109	
110	    const sessionLogMatch = SESSION_LOG_PATTERN.exec(pathname);
111	    if (req.method === 'GET' && sessionLogMatch) {
112	      const sessionId = decodeURIComponent(sessionLogMatch[1]);
113	      try {
114	        await handleSessionLog(req, res, db, sessionId, reqUrl.searchParams);
115	      } catch {
116	        writeJson(res, 500, { error: 'internal error' });
117	      }
118	      return;
119	    }
120	
121	    writeJson(res, 404, { error: 'not found' });
122	  });
123	}
