1	/**
2	 * HTTP endpoint — GET /api/sessions/:id/log integration tests.
3	 *
4	 * Spins up a real Node.js http.Server on a random port, inserts SQLite rows,
5	 * and makes real HTTP requests. No mocks.
6	 */
7	
8	import * as fs from 'fs';
9	import * as http from 'http';
10	import * as os from 'os';
11	import * as path from 'path';
12	import { afterEach, beforeEach, describe, expect, it } from 'vitest';
13	import { createHttpServer } from '../../src/server/api/http.js';
14	import { openDbPool } from '../../src/server/storage/db.js';
15	import { applyMigrations } from '../../src/server/storage/migrate.js';
16	
17	// ---------------------------------------------------------------------------
18	// Setup / teardown
19	// ---------------------------------------------------------------------------
20	
21	let tmpDir: string;
22	let db: ReturnType<typeof openDbPool>;
23	let server: http.Server;
24	let baseUrl: string;
25	
26	beforeEach(async () => {
27	  tmpDir = await fs.promises.mkdtemp(path.join(os.tmpdir(), 'yoke-http-'));
28	  db = openDbPool(path.join(tmpDir, 'test.db'));
29	  // Apply migrations so all tables exist.
30	  const migrationsDir = new URL(
31	    '../../src/server/storage/migrations/',
32	    import.meta.url,
33	  ).pathname;
34	  await applyMigrations(db.writer, migrationsDir);
35	
36	  // Insert the workflow row required by the sessions FK.
37	  db.writer
38	    .prepare(
39	      `INSERT INTO workflows (id, name, spec, pipeline, config, status, created_at, updated_at)
40	       VALUES ('wf-1', 'test-workflow', '{}', '{}', '{}', 'running', datetime('now'), datetime('now'))`,
41	    )
42	    .run();
43	
44	  server = createHttpServer(db);
45	  await new Promise<void>((resolve) => {
46	    server.listen(0, '127.0.0.1', () => resolve());
47	  });
48	  const addr = server.address() as { port: number };
49	  baseUrl = `http://127.0.0.1:${addr.port}`;
50	});
51	
52	afterEach(async () => {
53	  await new Promise<void>((resolve) => server.close(() => resolve()));
54	  db.close();
55	  await fs.promises.rm(tmpDir, { recursive: true, force: true });
56	});
57	
58	// ---------------------------------------------------------------------------
59	// Helpers
60	// ---------------------------------------------------------------------------
61	
62	interface HttpResult {
63	  status: number;
64	  body: unknown;
65	}
66	
67	async function get(urlStr: string): Promise<HttpResult> {
68	  return new Promise((resolve, reject) => {
69	    http
70	      .get(urlStr, (res) => {
71	        let data = '';
72	        res.on('data', (chunk) => (data += chunk));
73	        res.on('end', () => {
74	          try {
75	            resolve({ status: res.statusCode ?? 0, body: JSON.parse(data) });
76	          } catch {
77	            reject(new Error(`Failed to parse JSON response: ${data}`));
78	          }
79	        });
80	      })
81	      .on('error', reject);
82	  });
83	}
84	
85	let sessionSeq = 0;
86	
87	/** Insert a minimal sessions row. Returns the new session id. */
88	function insertSession(logPath: string | null = null): string {
89	  sessionSeq++;
90	  const id = `ses-${sessionSeq}`;
91	  db.writer
92	    .prepare(
93	      `INSERT INTO sessions
94	         (id, workflow_id, stage, phase, agent_profile, started_at, status, session_log_path)
95	       VALUES (?, 'wf-1', 'stage-1', 'phase-1', 'default', datetime('now'), 'running', ?)`,
96	    )
97	    .run(id, logPath);
98	  return id;
99	}
100	
101	/** Write n JSONL lines to a file in tmpDir; return its absolute path. */
102	async function makeLogFile(n: number, name = 'session.jsonl'): Promise<string> {
103	  const logPath = path.join(tmpDir, name);
104	  const lines = Array.from({ length: n }, (_, i) => `{"seq":${i}}`).join('\n');
105	  await fs.promises.writeFile(logPath, n > 0 ? lines + '\n' : '', 'utf8');
106	  return logPath;
107	}
108	
109	// ---------------------------------------------------------------------------
110	// 404 paths
111	// ---------------------------------------------------------------------------
112	
113	describe('GET /api/sessions/:id/log — 404 paths', () => {
114	  it('returns 404 for an unknown session id (AC-5)', async () => {
115	    const { status, body } = await get(`${baseUrl}/api/sessions/nonexistent/log`);
116	    expect(status).toBe(404);
117	    expect((body as any).error).toBe('session not found');
118	  });
119	
120	  it('returns 404 for an unknown route', async () => {
121	    const { status } = await get(`${baseUrl}/api/other/route`);
122	    expect(status).toBe(404);
123	  });
124	});
125	
126	// ---------------------------------------------------------------------------
127	// 200 — session exists, no log yet
128	// ---------------------------------------------------------------------------
129	
130	describe('GET /api/sessions/:id/log — session exists, no log', () => {
131	  it('returns 200 with empty entries when session_log_path is null (AC-5)', async () => {
132	    const id = insertSession(null);
133	    const { status, body } = await get(`${baseUrl}/api/sessions/${id}/log`);
134	    expect(status).toBe(200);
135	    const page = body as any;
136	    expect(page.entries).toEqual([]);
137	    expect(page.hasMore).toBe(false);
138	    expect(page.nextSeq).toBe(0);
139	  });
140	
141	  it('returns 200 with empty entries when log file does not yet exist', async () => {
142	    const logPath = path.join(tmpDir, 'not-yet-created.jsonl');
143	    const id = insertSession(logPath);
144	    const { status, body } = await get(`${baseUrl}/api/sessions/${id}/log`);
145	    expect(status).toBe(200);
146	    expect((body as any).entries).toEqual([]);
147	  });
148	});
149	
150	// ---------------------------------------------------------------------------
151	// 200 — paging correctness (AC-5)
152	// ---------------------------------------------------------------------------
153	
154	describe('GET /api/sessions/:id/log — paging correctness', () => {
155	  it('returns all entries in original order with sinceSeq=0 and large limit', async () => {
