    send(ws, { v: 1, type: 'subscribe', id: 'sub-5', payload: { workflowId: 'wf-6', sinceSeq: 4 } });
    const snap = await nextMessage(ws);
    expect(snap.type).toBe('workflow.snapshot');

    const r5 = await nextMessage(ws);
    const r6 = await nextMessage(ws);
    ws.close();

    expect(r5.seq).toBe(5);
    expect(r6.seq).toBe(6);
    expect(r5.type).toBe('stream.text');
    expect(r6.type).toBe('stream.text');
  });
});

// ---------------------------------------------------------------------------
// AC-3: subscription cap — 4 max; 5th → error + close 4002
// ---------------------------------------------------------------------------

describe('subscription cap (AC-3)', () => {
  it('allows 4 concurrent subscriptions', async () => {
    for (let i = 1; i <= 4; i++) insertWorkflow(`cap-wf-${i}`, `Cap Workflow ${i}`);

    const ws = await connectWs();
    await nextMessage(ws); // hello

    for (let i = 1; i <= 4; i++) {
      send(ws, { v: 1, type: 'subscribe', id: `sub-cap-${i}`, payload: { workflowId: `cap-wf-${i}` } });
      const snap = await nextMessage(ws);
      expect(snap.type).toBe('workflow.snapshot');
    }
    ws.close();
  });

  it('5th subscribe sends error{SUBSCRIPTION_LIMIT} and closes with 4002 (AC-3)', async () => {
    for (let i = 1; i <= 5; i++) insertWorkflow(`sl-wf-${i}`, `SL Workflow ${i}`);

    const ws = await connectWs();
    await nextMessage(ws); // hello

    // Subscribe to 4 workflows successfully.
    for (let i = 1; i <= 4; i++) {
      send(ws, { v: 1, type: 'subscribe', id: `sl-sub-${i}`, payload: { workflowId: `sl-wf-${i}` } });
      await nextMessage(ws); // snapshot
    }

    // 5th subscribe.
    const closeP = waitClose(ws);
    send(ws, { v: 1, type: 'subscribe', id: 'sl-sub-5', payload: { workflowId: 'sl-wf-5' } });

    const err = await nextMessage(ws);
    expect(err.type).toBe('error');
    expect((err.payload as any).code).toBe('SUBSCRIPTION_LIMIT');

    const { code } = await closeP;
    expect(code).toBe(4002);
  });

  it('re-subscribing to an already-subscribed workflowId does not count against the cap', async () => {
    insertWorkflow('recapwf');

    const ws = await connectWs();
    await nextMessage(ws); // hello

    // First subscribe.
    send(ws, { v: 1, type: 'subscribe', id: 'rc-sub-1', payload: { workflowId: 'recapwf' } });
    const snap1 = await nextMessage(ws);
    expect(snap1.type).toBe('workflow.snapshot');

    // Re-subscribe to same workflowId — should succeed (not counted again).
    send(ws, { v: 1, type: 'subscribe', id: 'rc-sub-2', payload: { workflowId: 'recapwf' } });
    const snap2 = await nextMessage(ws);
    ws.close();
    expect(snap2.type).toBe('workflow.snapshot');
  });
});

// ---------------------------------------------------------------------------
// AC-4: control commandId idempotency
// ---------------------------------------------------------------------------

describe('control commandId idempotency (AC-4)', () => {
  it('first control returns response; second with same commandId returns cached response', async () => {
    insertWorkflow('ctrl-wf');
    const ws = await connectWs();
    await nextMessage(ws); // hello

    const commandId = 'cmd-uuid-1234';
    const ctrlFrame = {
      v: 1,
      type: 'control',
      id: commandId,
      payload: { workflowId: 'ctrl-wf', action: 'pause' },
    };

    send(ws, ctrlFrame);
    const r1 = await nextMessage(ws);

    // Second call with same commandId — should get the same cached response.
    send(ws, ctrlFrame);
    const r2 = await nextMessage(ws);
    ws.close();

    // Both responses have the same type (the cached notice frame).
    expect(r1.type).toBe(r2.type);
    // The response content is identical (idempotent).
    expect(JSON.stringify(r1)).toBe(JSON.stringify(r2));
  });

  it('different commandIds yield independent responses', async () => {
    insertWorkflow('ctrl-wf2');
    const ws = await connectWs();
    await nextMessage(ws); // hello

    send(ws, { v: 1, type: 'control', id: 'cmd-A', payload: { workflowId: 'ctrl-wf2', action: 'pause' } });
    const rA = await nextMessage(ws);

    send(ws, { v: 1, type: 'control', id: 'cmd-B', payload: { workflowId: 'ctrl-wf2', action: 'resume' } });
    const rB = await nextMessage(ws);
    ws.close();

    // Both succeed but have distinct commandIds internally.
    expect(rA.type).toBeTruthy();
    expect(rB.type).toBeTruthy();
  });
});

// ---------------------------------------------------------------------------
// Ping / pong
// ---------------------------------------------------------------------------

describe('ping → pong', () => {
  it('pong frame has seq:0', async () => {
    const ws = await connectWs();
    await nextMessage(ws); // hello

    send(ws, { v: 1, type: 'ping', id: 'ping-1', payload: { clientTs: new Date().toISOString() } });
    const pong = await nextMessage(ws);
    ws.close();

    expect(pong.type).toBe('pong');
    expect(pong.seq).toBe(0);
  });
});

// ---------------------------------------------------------------------------
// Unsubscribe
// ---------------------------------------------------------------------------

describe('unsubscribe', () => {
  it('unsubscribing does not close the socket', async () => {
    insertWorkflow('unsub-wf');
    const ws = await connectWs();
    await nextMessage(ws); // hello

    send(ws, { v: 1, type: 'subscribe', id: 'usub-1', payload: { workflowId: 'unsub-wf' } });
    await nextMessage(ws); // snapshot

    send(ws, { v: 1, type: 'unsubscribe', id: 'usub-2', payload: { workflowId: 'unsub-wf' } });

    // Socket stays open — verify by sending ping and getting pong.
    send(ws, { v: 1, type: 'ping', id: 'usub-3', payload: { clientTs: new Date().toISOString() } });
    const pong = await nextMessage(ws);
    ws.close();
    expect(pong.type).toBe('pong');
  });
});

// ---------------------------------------------------------------------------
// Malformed frames
// ---------------------------------------------------------------------------

describe('malformed ClientFrame', () => {
  it('non-JSON message → error BAD_FRAME, socket stays open', async () => {
    const ws = await connectWs();
    await nextMessage(ws); // hello

    ws.send('this is not json');
    const err = await nextMessage(ws);

    expect(err.type).toBe('error');
    expect((err.payload as any).code).toBe('BAD_FRAME');

    // Socket is still open — send ping and get pong.
    send(ws, { v: 1, type: 'ping', id: 'bfp-1', payload: { clientTs: new Date().toISOString() } });
    const pong = await nextMessage(ws);
    ws.close();
    expect(pong.type).toBe('pong');
  });

  it('unknown frame type → error BAD_FRAME, socket stays open', async () => {
    const ws = await connectWs();
    await nextMessage(ws); // hello

    send(ws, { v: 1, type: 'unknown_type', id: 'unk-1', payload: {} });
    const err = await nextMessage(ws);
    expect(err.type).toBe('error');
    expect((err.payload as any).code).toBe('BAD_FRAME');
    ws.close();
  });
});

// ---------------------------------------------------------------------------
// AC-6: server binds 127.0.0.1 exclusively
// ---------------------------------------------------------------------------

describe('127.0.0.1 binding (AC-6)', () => {
  it('server listens on 127.0.0.1', () => {
    const addr = handle.fastify.server.address() as AddressInfo;
    expect(addr.address).toBe('127.0.0.1');
  });

  it('listenServer throws if host is not 127.0.0.1', async () => {
    const { listenServer } = await import('../../src/server/api/server.js');
    // TypeScript prevents passing a non-127.0.0.1 string, so cast.
    await expect(
      listenServer(db, { host: '0.0.0.0' as '127.0.0.1' }),
    ).rejects.toThrow('127.0.0.1');
  });
});

// ---------------------------------------------------------------------------
// seq rules — non-session frames use seq:0 (RC)
// ---------------------------------------------------------------------------

describe('seq rules (RC)', () => {
  it('hello frame has seq:0 (non-session frame)', async () => {
    const ws = await connectWs();
    const hello = await nextMessage(ws);
    ws.close();
    expect(hello.seq).toBe(0);
  });

  it('workflow.snapshot frame has seq:0 (non-session frame)', async () => {
    insertWorkflow('seq-wf');
    const ws = await connectWs();
    await nextMessage(ws); // hello

    send(ws, { v: 1, type: 'subscribe', id: 's-1', payload: { workflowId: 'seq-wf' } });
    const snap = await nextMessage(ws);
    ws.close();
    expect(snap.seq).toBe(0);
  });

  it('backfill frames preserve original seq from buffer (RC: seq rules)', async () => {
    insertWorkflow('seq-wf2');
    const sessionId = insertSession('seq-wf2', 'seq-ses');

    // Push frames with specific seq values.
    const frames = [7, 8, 9].map((seq) =>
      makeFrame('stream.thinking', { textDelta: 'x' }, { workflowId: 'seq-wf2', sessionId, seq }),
    );
    frames.forEach((f) => handle.state.backfillBuffer.push(sessionId, f));

    const ws = await connectWs();
    await nextMessage(ws); // hello

    send(ws, { v: 1, type: 'subscribe', id: 'seq-sub', payload: { workflowId: 'seq-wf2', sinceSeq: 6 } });
    await nextMessage(ws); // snapshot

    const r7 = await nextMessage(ws);
    const r8 = await nextMessage(ws);
    const r9 = await nextMessage(ws);
    ws.close();

    expect(r7.seq).toBe(7);
    expect(r8.seq).toBe(8);
    expect(r9.seq).toBe(9);
  });
});

