describe('GET /api/workflows/:id/usage/timeseries', () => {
  it('returns 200 for known workflow (AC-5)', async () => {
    const id = insertWorkflow();
    insertSession(id);

    const { statusCode, body } = await inject('GET', `/api/workflows/${id}/usage/timeseries`);
