  });

  it('snapshot includes active sessions', async () => {
    insertWorkflow('wf-3');
    insertSession('wf-3', 'ses-a');

    const s = await connectWs();
    await s.next(); // hello

    s.send({ v: 1, type: 'subscribe', id: 'sub-2', payload: { workflowId: 'wf-3' } });
